_MODULES["ui.components"] = function()
-- UI primitives: Section, Label, Button, Toggle, Slider, KeybindSetter.
-- Sharp angular corners — no UICorner anywhere — to match the hex/HUD theme.

local theme = require("ui.theme")

local UIS = game:GetService("UserInputService")

local components = {}

local function baseRow(parent, height)
    local f = Instance.new("Frame")
    f.Size = UDim2.new(1, 0, 0, height or theme.rowHeight)
    f.BackgroundColor3 = theme.bgAlt
    f.BorderSizePixel = 0
    f.Parent = parent
    return f
end

function components.Section(parent, text)
    local f = Instance.new("TextLabel")
    f.Size = UDim2.new(1, 0, 0, 22)
    f.BackgroundTransparency = 1
    f.Text = string.upper(text or "")
    f.TextColor3 = theme.accent
    f.Font = theme.fontBold
    f.TextSize = 11
    f.TextXAlignment = Enum.TextXAlignment.Left
    f.Parent = parent
    return f
end

function components.Label(parent, text)
    local f = Instance.new("TextLabel")
    f.Size = UDim2.new(1, 0, 0, 20)
    f.BackgroundTransparency = 1
    f.Text = text or ""
    f.TextColor3 = theme.fgDim
    f.Font = theme.font
    f.TextSize = 12
    f.TextXAlignment = Enum.TextXAlignment.Left
    f.Parent = parent
    return f
end

function components.Button(parent, opts)
    opts = opts or {}
    local f = baseRow(parent)
    local btn = Instance.new("TextButton")
    btn.Size = UDim2.fromScale(1, 1)
    btn.BackgroundTransparency = 1
    btn.Text = opts.text or "Button"
    btn.TextColor3 = theme.fg
    btn.Font = theme.font
    btn.TextSize = 13
    btn.Parent = f
    if opts.onClick then
        btn.MouseButton1Click:Connect(opts.onClick)
    end
    return f
end

function components.Toggle(parent, opts)
    opts = opts or {}
    local state = opts.default == true
    local f = baseRow(parent)

    local label = Instance.new("TextLabel")
    label.Size = UDim2.new(1, -56, 1, 0)
    label.Position = UDim2.fromOffset(10, 0)
    label.BackgroundTransparency = 1
    label.Text = opts.text or "Toggle"
    label.TextColor3 = theme.fg
    label.Font = theme.font
    label.TextSize = 12
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Parent = f

    local switch = Instance.new("TextButton")
    switch.Size = UDim2.fromOffset(36, 18)
    switch.Position = UDim2.new(1, -44, 0.5, -9)
    switch.AutoButtonColor = false
    switch.Text = ""
    switch.Parent = f

    local knob = Instance.new("Frame")
    knob.Size = UDim2.fromOffset(14, 14)
    knob.BackgroundColor3 = theme.fg
    knob.BorderSizePixel = 0
    knob.Parent = switch

    local function apply()
        switch.BackgroundColor3 = state and theme.accent or theme.bgDark
        knob.Position = state and UDim2.new(1, -16, 0.5, -7) or UDim2.fromOffset(2, 2)
    end
    apply()

    switch.MouseButton1Click:Connect(function()
        state = not state
        apply()
        if opts.onChange then opts.onChange(state) end
    end)

    local api = {}
    function api:Set(v)
        v = v and true or false
        if state ~= v then
            state = v
            apply()
            if opts.onChange then opts.onChange(state) end
        end
    end
    function api:Get() return state end
    return api
end

function components.Slider(parent, opts)
    opts = opts or {}
    local min   = opts.min or 0
    local max   = opts.max or 100
    local step  = opts.step or 1
    local value = opts.default or min

    local f = baseRow(parent, 42)

    local label = Instance.new("TextLabel")
    label.Size = UDim2.new(1, -20, 0, 18)
    label.Position = UDim2.fromOffset(10, 2)
    label.BackgroundTransparency = 1
    label.Font = theme.font
    label.TextSize = 12
    label.TextColor3 = theme.fg
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Text = string.format("%s: %s", opts.text or "Slider", tostring(value))
    label.Parent = f

    local track = Instance.new("Frame")
    track.Size = UDim2.new(1, -20, 0, 6)
    track.Position = UDim2.fromOffset(10, 26)
    track.BackgroundColor3 = theme.bgDark
    track.BorderSizePixel = 0
    track.Parent = f

    local fill = Instance.new("Frame")
    fill.BackgroundColor3 = theme.accent
    fill.BorderSizePixel = 0
    fill.Size = UDim2.new((value - min) / (max - min), 0, 1, 0)
    fill.Parent = track

    local dragging = false

    local function setFromX(x)
        local relX = math.clamp(x - track.AbsolutePosition.X, 0, track.AbsoluteSize.X)
        local pct = (track.AbsoluteSize.X == 0) and 0 or relX / track.AbsoluteSize.X
        local v = min + pct * (max - min)
        v = math.floor(v / step + 0.5) * step
        v = math.clamp(v, min, max)
        if math.abs(v - value) > 1e-6 then
            value = v
            fill.Size = UDim2.new((v - min) / (max - min), 0, 1, 0)
            label.Text = string.format("%s: %s", opts.text or "Slider", tostring(v))
            if opts.onChange then opts.onChange(v) end
        end
    end

    track.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
           or input.UserInputType == Enum.UserInputType.Touch then
            dragging = true
            setFromX(input.Position.X)
        end
    end)
    UIS.InputChanged:Connect(function(input)
        if not dragging then return end
        if input.UserInputType == Enum.UserInputType.MouseMovement
           or input.UserInputType == Enum.UserInputType.Touch then
            setFromX(input.Position.X)
        end
    end)
    UIS.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
           or input.UserInputType == Enum.UserInputType.Touch then
            dragging = false
        end
    end)

    local api = {}
    function api:Get() return value end
    function api:Set(v)
        v = math.clamp(v, min, max)
        value = v
        fill.Size = UDim2.new((v - min) / (max - min), 0, 1, 0)
        label.Text = string.format("%s: %s", opts.text or "Slider", tostring(v))
        if opts.onChange then opts.onChange(v) end
    end
    return api
end

local function keyDisplayName(k)
    if not k or k == Enum.KeyCode.Unknown then return "<none>" end
    return (tostring(k):gsub("Enum.KeyCode.", ""))
end

function components.KeybindSetter(parent, opts)
    opts = opts or {}
    local current = opts.default or Enum.KeyCode.Unknown
    local listening = false

    local f = baseRow(parent, 28)

    local label = Instance.new("TextLabel")
    label.Size = UDim2.new(0.5, -10, 1, 0)
    label.Position = UDim2.fromOffset(10, 0)
    label.BackgroundTransparency = 1
    label.Text = opts.label or "Keybind"
    label.TextColor3 = theme.fg
    label.Font = theme.font
    label.TextSize = 12
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Parent = f

    -- Setter button (click to enter listen mode, then press any key to bind)
    local btn = Instance.new("TextButton")
    btn.Position = UDim2.new(0.5, 4, 0.5, -10)
    btn.Size = UDim2.new(0.5, -38, 0, 20)
    btn.BackgroundColor3 = theme.bgDark
    btn.AutoButtonColor = false
    btn.TextColor3 = theme.fgDim
    btn.Font = theme.fontMono
    btn.TextSize = 11
    btn.Text = keyDisplayName(current)
    btn.Parent = f

    -- Unbind button: clears the keybind in one click
    local unbind = Instance.new("TextButton")
    unbind.Position = UDim2.new(1, -22, 0.5, -10)
    unbind.Size = UDim2.fromOffset(20, 20)
    unbind.BackgroundColor3 = theme.danger
    unbind.AutoButtonColor = false
    unbind.Text = "X"
    unbind.TextColor3 = theme.fg
    unbind.Font = theme.fontBold
    unbind.TextSize = 10
    unbind.Parent = f

    btn.MouseButton1Click:Connect(function()
        if listening then return end
        listening = true
        btn.Text = "<press a key>"
        btn.BackgroundColor3 = theme.accent

        local conn
        conn = UIS.InputBegan:Connect(function(input)
            if input.UserInputType ~= Enum.UserInputType.Keyboard then return end
            if input.KeyCode == Enum.KeyCode.Unknown then return end
            local k = input.KeyCode
            if k == Enum.KeyCode.Escape then
                listening = false
                btn.Text = keyDisplayName(current)
                btn.BackgroundColor3 = theme.bgDark
                conn:Disconnect()
                return
            end
            if k == Enum.KeyCode.Backspace then
                current = Enum.KeyCode.Unknown
                listening = false
                btn.Text = keyDisplayName(current)
                btn.BackgroundColor3 = theme.bgDark
                if opts.onChange then opts.onChange(current) end
                conn:Disconnect()
                return
            end
            current = k
            listening = false
            btn.Text = keyDisplayName(current)
            btn.BackgroundColor3 = theme.bgDark
            if opts.onChange then opts.onChange(current) end
            conn:Disconnect()
        end)
    end)

    unbind.MouseButton1Click:Connect(function()
        current = Enum.KeyCode.Unknown
        btn.Text = keyDisplayName(current)
        if opts.onChange then opts.onChange(current) end
    end)

    return {
        get = function() return current end,
        set = function(k)
            current = k
            btn.Text = keyDisplayName(current)
            if opts.onChange then opts.onChange(current) end
        end,
    }
end

return components
end

_MODULES["ui.window"] = function()
-- Pantheon root UI. Hosts a ScreenGui that contains a `Containers` parent (for
-- draggable category windows) plus a floating hexagonal open/close button.
-- Master hotkey (default RightControl) toggles visibility.

local env      = require("core.env")
local theme    = require("ui.theme")
local keybinds = require("core.keybinds")

local UIS = game:GetService("UserInputService")

local Window = {}

local s = {
    screenGui = nil,
    container = nil,
    openBtn   = nil,
    visible   = true,
    masterKey = Enum.KeyCode.RightControl,
}

-- Flat-top hex P button. ClipsDescendants on host clips the two rotated
-- diamonds at the top and bottom edges, creating the flat top/bottom of the
-- hex shape. The diamonds' horizontal vertices align with the host width,
-- and the middle rectangle covers the diamonds' inner halves so the silhouette
-- is one continuous hexagon.
local function buildHexButton(sg)
    local host = Instance.new("Frame")
    host.Name = "PantheonOpenButton"
    host.Size = UDim2.fromOffset(46, 50)
    host.Position = UDim2.new(0, 16, 1, -66)
    host.BackgroundTransparency = 1
    host.ClipsDescendants = true
    host.ZIndex = 10
    host.Parent = sg

    -- Top half: rotated square centered at y=12.5. Its top vertex extends
    -- above the host (clipped at y=0 -> flat top). Side vertices at y=12.5
    -- align with the middle rectangle's top edge.
    local top = Instance.new("Frame")
    top.Size = UDim2.fromOffset(33, 33)
    top.AnchorPoint = Vector2.new(0.5, 0.5)
    top.Position = UDim2.new(0.5, 0, 0, 12.5)
    top.Rotation = 45
    top.BackgroundColor3 = theme.accent
    top.BorderSizePixel = 0
    top.ZIndex = 10
    top.Parent = host

    -- Middle rectangle (y=12.5 to y=37.5)
    local mid = Instance.new("Frame")
    mid.Size = UDim2.new(1, 0, 0, 25)
    mid.Position = UDim2.fromOffset(0, 12.5)
    mid.BackgroundColor3 = theme.accent
    mid.BorderSizePixel = 0
    mid.ZIndex = 11
    mid.Parent = host

    -- Bottom half: rotated square centered at y=37.5, bottom vertex clipped
    -- at y=50 -> flat bottom.
    local bot = Instance.new("Frame")
    bot.Size = UDim2.fromOffset(33, 33)
    bot.AnchorPoint = Vector2.new(0.5, 0.5)
    bot.Position = UDim2.new(0.5, 0, 0, 37.5)
    bot.Rotation = 45
    bot.BackgroundColor3 = theme.accent
    bot.BorderSizePixel = 0
    bot.ZIndex = 10
    bot.Parent = host

    local label = Instance.new("TextLabel")
    label.Size = UDim2.fromScale(1, 1)
    label.BackgroundTransparency = 1
    label.Text = "P"
    label.TextColor3 = theme.fg
    label.Font = theme.fontBold
    label.TextSize = 20
    label.ZIndex = 12
    label.Parent = host

    local btn = Instance.new("TextButton")
    btn.Size = UDim2.fromScale(1, 1)
    btn.BackgroundTransparency = 1
    btn.Text = ""
    btn.AutoButtonColor = false
    btn.ZIndex = 13
    btn.Parent = host

    -- Drag + click-to-toggle (click only fires if not dragged)
    local dragging, dragStart, startPos = false, nil, nil
    local moved = false
    btn.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
           or input.UserInputType == Enum.UserInputType.Touch then
            dragging  = true
            dragStart = input.Position
            startPos  = host.Position
            moved     = false
        end
    end)
    UIS.InputChanged:Connect(function(input)
        if not dragging then return end
        if input.UserInputType == Enum.UserInputType.MouseMovement
           or input.UserInputType == Enum.UserInputType.Touch then
            local delta = input.Position - dragStart
            if delta.Magnitude > 4 then moved = true end
            host.Position = UDim2.new(
                startPos.X.Scale, startPos.X.Offset + delta.X,
                startPos.Y.Scale, startPos.Y.Offset + delta.Y
            )
        end
    end)
    UIS.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1
           or input.UserInputType == Enum.UserInputType.Touch then
            if dragging and not moved then Window.toggle() end
            dragging = false
        end
    end)

    return host
end

function Window.init()
    if s.screenGui then return end

    local sg = Instance.new("ScreenGui")
    sg.Name = "PantheonGui"
    sg.IgnoreGuiInset = true
    sg.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
    sg.ResetOnSpawn = false
    sg.Parent = env.guiParent()
    env.protectGui(sg)

    local containerHost = Instance.new("Frame")
    containerHost.Name = "Containers"
    containerHost.Size = UDim2.fromScale(1, 1)
    containerHost.BackgroundTransparency = 1
    containerHost.Parent = sg

    s.screenGui = sg
    s.container = containerHost
    s.openBtn   = buildHexButton(sg)

    keybinds.set("ui.master_toggle", s.masterKey, Window.toggle)
end

function Window.toggle()
    Window.setVisible(not s.visible)
end

function Window.setVisible(v)
    s.visible = v
    if s.container then s.container.Visible = v end
end

function Window.isVisible()
    return s.visible
end

function Window.parent()
    return s.container
end

function Window.setMasterKey(key)
    s.masterKey = key
    keybinds.set("ui.master_toggle", key, Window.toggle)
end

return Window
end

_MODULES["ui.container"] = function()
-- Draggable category window. Holds feature rows. Wurst-style — stacks left-to-right
-- by default; user can drag them anywhere. Sharp corners with rotated-square
-- diamond accents at each corner for a hex/HUD look.

local theme = require("ui.theme")

local UIS = game:GetService("UserInputService")

local Container = {}
Container.__index = Container

local nextIndex = 0

local function cornerDiamond(parent, position, color)
    local d = Instance.new("Frame")
    d.Size = UDim2.fromOffset(10, 10)
    d.Position = position
    d.AnchorPoint = Vector2.new(0.5, 0.5)
    d.Rotation = 45
    d.BackgroundColor3 = color
    d.BorderSizePixel = 0
    d.ZIndex = 5
    d.Parent = parent
end

local function addCornerDiamonds(parent, color)
    cornerDiamond(parent, UDim2.new(0, 0, 0, 0), color) -- TL
    cornerDiamond(parent, UDim2.new(1, 0, 0, 0), color) -- TR
    cornerDiamond(parent, UDim2.new(0, 0, 1, 0), color) -- BL
    cornerDiamond(parent, UDim2.new(1, 0, 1, 0), color) -- BR
end

function Container.new(parent, name)
    local self = setmetatable({}, Container)

    local idx = nextIndex
    nextIndex = nextIndex + 1
    local x = 16 + idx * (theme.containerWidth + theme.containerGap)

    local root = Instance.new("Frame")
    root.Name = "Container_" .. name
    root.Size = UDim2.new(0, theme.containerWidth, 0, 28)
    root.AutomaticSize = Enum.AutomaticSize.Y
    root.Position = UDim2.fromOffset(x, 16)
    root.BackgroundColor3 = theme.bg
    root.BorderSizePixel = 0
    root.Parent = parent

    local stroke = Instance.new("UIStroke", root)
    stroke.Color = theme.border
    stroke.Thickness = 1

    -- Header
    local header = Instance.new("TextLabel")
    header.Name = "Header"
    header.Size = UDim2.new(1, 0, 0, 28)
    header.BackgroundColor3 = theme.accent
    header.BorderSizePixel = 0
    header.Text = name
    header.TextColor3 = theme.fg
    header.Font = theme.fontBold
    header.TextSize = 13
    header.Parent = root

    -- Features stack
    local features = Instance.new("Frame")
    features.Name = "Features"
    features.Position = UDim2.fromOffset(0, 28)
    features.Size = UDim2.new(1, 0, 0, 0)
    features.AutomaticSize = Enum.AutomaticSize.Y
    features.BackgroundTransparency = 1
    features.Parent = root

    local list = Instance.new("UIListLayout", features)
    list.SortOrder = Enum.SortOrder.LayoutOrder
    list.Padding = UDim.new(0, 1)

    -- Corner diamonds (added last so they render on top of stroke + header)
    addCornerDiamonds(root, theme.accent)

    -- Drag on header
    do
        local dragging, dragStart, startPos = false, nil, nil
        header.InputBegan:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.MouseButton1
               or input.UserInputType == Enum.UserInputType.Touch then
                dragging  = true
                dragStart = input.Position
                startPos  = root.Position
            end
        end)
        UIS.InputChanged:Connect(function(input)
            if not dragging then return end
            if input.UserInputType == Enum.UserInputType.MouseMovement
               or input.UserInputType == Enum.UserInputType.Touch then
                local delta = input.Position - dragStart
                root.Position = UDim2.new(
                    startPos.X.Scale, startPos.X.Offset + delta.X,
                    startPos.Y.Scale, startPos.Y.Offset + delta.Y
                )
            end
        end)
        UIS.InputEnded:Connect(function(input)
            if input.UserInputType == Enum.UserInputType.MouseButton1
               or input.UserInputType == Enum.UserInputType.Touch then
                dragging = false
            end
        end)
    end

    self.root     = root
    self.features = features
    self.name     = name
    self._count   = 0

    return self
end

function Container:add(featureRoot)
    self._count = self._count + 1
    featureRoot.LayoutOrder = self._count
    featureRoot.Parent = self.features
    return self
end

return Container
end

_MODULES["ui.feature"] = function()
-- Feature row: [name] [ON/OFF indicator] [i info] [cog].
-- Cog click expands an inline settings panel below the row.
-- "i" click expands a description label below the row (separate from settings).
-- Sharp angular corners throughout.
--
-- Settings types: toggle, slider, button, section.

local theme      = require("ui.theme")
local keybinds   = require("core.keybinds")
local components = require("ui.components")

local Feature = {}

local nextId = 0

function Feature.declare(def)
    nextId = nextId + 1
    local id = def.id or ("feature_" .. nextId)
    local hasDesc = def.description and #def.description > 0

    -- Root uses UIListLayout so row / description / settings panel stack
    -- vertically and only contribute height when Visible = true.
    local root = Instance.new("Frame")
    root.Name = "Feature_" .. id
    root.Size = UDim2.new(1, 0, 0, 0)
    root.AutomaticSize = Enum.AutomaticSize.Y
    root.BackgroundTransparency = 1

    local rootList = Instance.new("UIListLayout", root)
    rootList.SortOrder = Enum.SortOrder.LayoutOrder

    -- Row
    local row = Instance.new("Frame")
    row.Size = UDim2.new(1, 0, 0, theme.featureHeight)
    row.BackgroundColor3 = theme.bgAlt
    row.BorderSizePixel = 0
    row.LayoutOrder = 1
    row.Parent = root

    -- Reserve right-side space: indicator(40) + i(20) + cog(20) + gaps = ~108
    local nameLabel = Instance.new("TextLabel")
    nameLabel.Position = UDim2.fromOffset(8, 0)
    nameLabel.Size = UDim2.new(1, hasDesc and -108 or -84, 1, 0)
    nameLabel.BackgroundTransparency = 1
    nameLabel.Text = def.name or "Feature"
    nameLabel.TextColor3 = theme.fgDim
    nameLabel.Font = theme.font
    nameLabel.TextSize = 13
    nameLabel.TextXAlignment = Enum.TextXAlignment.Left
    nameLabel.Parent = row

    local indicator = Instance.new("TextButton")
    indicator.Position = UDim2.new(1, hasDesc and -100 or -76, 0.5, -10)
    indicator.Size = UDim2.fromOffset(40, 20)
    indicator.BackgroundColor3 = theme.off
    indicator.AutoButtonColor = false
    indicator.Text = "OFF"
    indicator.TextColor3 = theme.fg
    indicator.Font = theme.fontBold
    indicator.TextSize = 10
    indicator.Parent = row

    local info -- info "i" button, only if a description was provided
    if hasDesc then
        info = Instance.new("TextButton")
        info.Position = UDim2.new(1, -52, 0.5, -10)
        info.Size = UDim2.fromOffset(20, 20)
        info.BackgroundColor3 = theme.bgDark
        info.AutoButtonColor = false
        info.Text = "i"
        info.TextColor3 = theme.fgDim
        info.Font = theme.fontBold
        info.TextSize = 12
        info.Parent = row
    end

    local cog = Instance.new("TextButton")
    cog.Position = UDim2.new(1, -28, 0.5, -10)
    cog.Size = UDim2.fromOffset(20, 20)
    cog.BackgroundColor3 = theme.bgDark
    cog.AutoButtonColor = false
    cog.Text = "\u{2699}"
    cog.TextColor3 = theme.fgDim
    cog.Font = theme.font
    cog.TextSize = 14
    cog.Parent = row

    -- Description label (hidden until "i" clicked)
    local desc
    if hasDesc then
        desc = Instance.new("TextLabel")
        desc.Size = UDim2.new(1, 0, 0, 0)
        desc.AutomaticSize = Enum.AutomaticSize.Y
        desc.BackgroundColor3 = theme.bgDark
        desc.BorderSizePixel = 0
        desc.Text = def.description
        desc.TextColor3 = theme.fgDim
        desc.Font = theme.font
        desc.TextSize = 11
        desc.TextWrapped = true
        desc.TextXAlignment = Enum.TextXAlignment.Left
        desc.TextYAlignment = Enum.TextYAlignment.Top
        desc.Visible = false
        desc.LayoutOrder = 2
        desc.Parent = root

        local pad = Instance.new("UIPadding", desc)
        pad.PaddingTop    = UDim.new(0, 6)
        pad.PaddingBottom = UDim.new(0, 6)
        pad.PaddingLeft   = UDim.new(0, 8)
        pad.PaddingRight  = UDim.new(0, 8)
    end

    -- Settings panel (hidden until cog clicked)
    local panel = Instance.new("Frame")
    panel.Size = UDim2.new(1, 0, 0, 0)
    panel.AutomaticSize = Enum.AutomaticSize.Y
    panel.BackgroundColor3 = theme.bgDark
    panel.BorderSizePixel = 0
    panel.Visible = false
    panel.LayoutOrder = 3
    panel.Parent = root

    local panelPad = Instance.new("UIPadding", panel)
    panelPad.PaddingTop    = UDim.new(0, 4)
    panelPad.PaddingBottom = UDim.new(0, 4)
    panelPad.PaddingLeft   = UDim.new(0, 6)
    panelPad.PaddingRight  = UDim.new(0, 6)

    local panelList = Instance.new("UIListLayout", panel)
    panelList.Padding   = UDim.new(0, 4)
    panelList.SortOrder = Enum.SortOrder.LayoutOrder

    -- Toggle state
    local enabled = def.default == true

    local function applyToggle()
        indicator.BackgroundColor3 = enabled and theme.on or theme.off
        indicator.Text = enabled and "ON" or "OFF"
        nameLabel.TextColor3 = enabled and theme.fg or theme.fgDim
        if def.onToggle then
            local ok, err = pcall(def.onToggle, enabled)
            if not ok then warn("[Pantheon] feature onToggle error:", err) end
        end
    end

    local function setEnabled(v)
        v = v and true or false
        if enabled ~= v then
            enabled = v
            applyToggle()
        end
    end

    local function toggleEnabled()
        setEnabled(not enabled)
    end

    indicator.MouseButton1Click:Connect(toggleEnabled)

    -- Cog: toggle settings panel
    local panelOpen = false
    cog.MouseButton1Click:Connect(function()
        panelOpen = not panelOpen
        panel.Visible = panelOpen
        cog.BackgroundColor3 = panelOpen and theme.accent or theme.bgDark
    end)

    -- Info: toggle description label
    if info then
        local descOpen = false
        info.MouseButton1Click:Connect(function()
            descOpen = not descOpen
            desc.Visible = descOpen
            info.BackgroundColor3 = descOpen and theme.accent or theme.bgDark
        end)
    end

    -- Keybind dispatch
    local function onPress()
        if def.onKey then
            local ok, err = pcall(def.onKey)
            if not ok then warn("[Pantheon] feature onKey error:", err) end
        else
            toggleEnabled()
        end
    end

    local function onRelease()
        if def.onKeyRelease then
            local ok, err = pcall(def.onKeyRelease)
            if not ok then warn("[Pantheon] feature onKeyRelease error:", err) end
        end
    end

    if def.defaultKey then
        keybinds.set(id, def.defaultKey, onPress, onRelease)
    end

    -- Settings panel content: keybind setter first
    components.KeybindSetter(panel, {
        label    = "Keybind",
        default  = def.defaultKey,
        onChange = function(newKey)
            keybinds.set(id, newKey, onPress, onRelease)
        end,
    })

    if def.settings and #def.settings > 0 then
        local sep = Instance.new("Frame")
        sep.Size = UDim2.new(1, 0, 0, 1)
        sep.BackgroundColor3 = theme.border
        sep.BorderSizePixel = 0
        sep.Parent = panel

        for _, opt in ipairs(def.settings) do
            if opt.type == "section" then
                components.Section(panel, opt.name)
            elseif opt.type == "toggle" then
                components.Toggle(panel, {
                    text     = opt.name,
                    default  = opt.default,
                    onChange = opt.onChange,
                })
            elseif opt.type == "slider" then
                components.Slider(panel, {
                    text     = opt.name,
                    min      = opt.min,
                    max      = opt.max,
                    step     = opt.step,
                    default  = opt.default,
                    onChange = opt.onChange,
                })
            elseif opt.type == "button" then
                components.Button(panel, {
                    text    = opt.name,
                    onClick = opt.onClick,
                })
            elseif opt.type == "keybind" then
                if opt.default and opt.id then
                    keybinds.set(opt.id, opt.default, opt.onPress, opt.onRelease)
                end
                components.KeybindSetter(panel, {
                    label    = opt.name or "Key",
                    default  = opt.default,
                    onChange = function(newKey)
                        if opt.id then
                            keybinds.set(opt.id, newKey, opt.onPress, opt.onRelease)
                        end
                    end,
                })
            end
        end
    end

    applyToggle()

    return {
        root       = root,
        id         = id,
        setEnabled = setEnabled,
        getEnabled = function() return enabled end,
    }
end

return Feature
end

_MODULES["ui.notify"] = function()
-- Stacked corner toasts. Stateless caller API.

local env   = require("core.env")
local theme = require("ui.theme")

local notify = {}
local container

local function ensureContainer()
    if container and container.Parent then return container end
    local sg = Instance.new("ScreenGui")
    sg.Name = "PantheonNotify"
    sg.IgnoreGuiInset = true
    sg.ResetOnSpawn = false
    sg.Parent = env.guiParent()
    env.protectGui(sg)

    local f = Instance.new("Frame")
    f.AnchorPoint = Vector2.new(1, 1)
    f.Position = UDim2.new(1, -16, 1, -16)
    f.Size = UDim2.new(0, 300, 1, -32)
    f.BackgroundTransparency = 1
    f.Parent = sg

    local list = Instance.new("UIListLayout", f)
    list.VerticalAlignment = Enum.VerticalAlignment.Bottom
    list.SortOrder = Enum.SortOrder.LayoutOrder
    list.Padding = UDim.new(0, 6)

    container = f
    return f
end

local function toast(text, duration, color)
    duration = duration or 3
    local parent = ensureContainer()

    local frame = Instance.new("Frame")
    frame.Size = UDim2.new(1, 0, 0, 0)
    frame.AutomaticSize = Enum.AutomaticSize.Y
    frame.BackgroundColor3 = theme.bgAlt
    frame.BorderSizePixel = 0
    frame.Parent = parent
    Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 6)

    local accent = Instance.new("Frame")
    accent.Size = UDim2.new(0, 3, 1, 0)
    accent.BackgroundColor3 = color or theme.accent
    accent.BorderSizePixel = 0
    accent.Parent = frame

    local label = Instance.new("TextLabel")
    label.Size = UDim2.new(1, -20, 0, 0)
    label.Position = UDim2.fromOffset(12, 0)
    label.AutomaticSize = Enum.AutomaticSize.Y
    label.BackgroundTransparency = 1
    label.Text = text or ""
    label.TextColor3 = theme.fg
    label.Font = theme.font
    label.TextSize = 13
    label.TextWrapped = true
    label.TextXAlignment = Enum.TextXAlignment.Left
    label.Parent = frame

    local pad = Instance.new("UIPadding", frame)
    pad.PaddingTop = UDim.new(0, 8)
    pad.PaddingBottom = UDim.new(0, 8)

    task.delay(duration, function()
        if frame and frame.Parent then frame:Destroy() end
    end)
end

function notify.info(text, duration)    toast(text, duration, theme.accent)  end
function notify.success(text, duration) toast(text, duration, theme.success) end
function notify.warn(text, duration)    toast(text, duration, theme.danger)  end

notify.toast = toast

return notify
end

_MODULES["games.registry"] = function()
-- Per-game module registry. Keys are tostring(PlaceId).
-- A game module is just a table with a .register(window) function.

local games = {}
local registry = {}

function registry.register(placeId, mod)
    games[tostring(placeId)] = mod
end

function registry.current()
    return games[tostring(game.PlaceId)]
end

function registry.all()
    return games
end

return registry
end

_MODULES["modules.aim.state"] = function()
-- Shared state for the aim-assist subsystem.
-- Target Select writes the target; Lock-On (camera) and Rotation Lock read it.

local Signal = require("core.signal")

local state = {
    -- Target (set by Target Select, read by Lock-On / Rotation Lock / Highlight)
    target              = nil,
    target_type         = nil, -- "player" or "npc"

    -- Target Select
    target_select_enabled = false,

    -- Targeting filters
    realisticEnabled       = false,
    checkHealthEnabled     = true,
    visibilityCheckEnabled = false,
    rangeLimit             = 0,    -- 0 = infinite

    -- Lock-On master + sub-toggles
    lockon_enabled       = false,
    cameraLockEnabled    = true,   -- camera force on/off
    rotationLockEnabled  = false,  -- rotation lock on/off (was lockonPlusEnabled)
    bgSafeEnabled        = true,   -- battlegrounds-safe modifier on rotation lock

    -- Resistance (modifies camera lock)
    resistance_enabled   = false,
    resistance_threshold = 5,
    resistance_strength  = 0.5,

    -- Highlight
    highlightEnabled       = true,
    highlightSecondEnabled = false,
    selfFadeEnabled        = false,

    -- Shiftlock
    shiftlock_enabled = false,
    shiftlock_active  = false,
    killForeign       = true,

    -- Swap
    swap_enabled = true,

    -- Misc
    lockHeightOffset = 0,
    friendlies       = {},

    -- Signals
    onTargetChanged = Signal.new(),
}

function state.setTarget(target, type_)
    if state.target ~= target then
        state.target = target
        state.target_type = type_
        state.onTargetChanged:Fire(target, type_)
    end
end

function state.isFriendly(plr)
    if not plr or not plr.UserId then return false end
    return state.friendlies[plr.UserId] == true
end

return state
end

_MODULES["modules.aim.targeting"] = function()
-- Target picking. Ports LockOnTargetingModule. Pure — does not mutate aim state.

local state = require("modules.aim.state")

local Players   = game:GetService("Players")
local Workspace = game:GetService("Workspace")

local Targeting = {}

local function rootOf(char)
    return char and char:FindFirstChild("HumanoidRootPart")
end

local function isInFront(root)
    if not state.realisticEnabled then return true end
    local cam = Workspace.CurrentCamera
    if not cam then return true end
    local camCF = cam.CFrame
    local toTarget = root.Position - camCF.Position
    local mag = toTarget.Magnitude
    if mag <= 0.01 then return false end
    return (toTarget / mag):Dot(camCF.LookVector) >= math.cos(math.rad(60))
end

local function isAlive(char)
    if not char then return false end
    local hum = char:FindFirstChildOfClass("Humanoid")
    if not hum then return false end
    if state.checkHealthEnabled then
        if hum.Health <= 0 then return false end
        if char:FindFirstChildOfClass("ForceField") then return false end
    end
    return true
end

local function isVisible(plr)
    local char = plr.Character
    local root = rootOf(char)
    if not root then return false end
    local cam = Workspace.CurrentCamera
    if not cam then return true end

    local origin = cam.CFrame.Position
    local direction = root.Position - origin
    if direction.Magnitude <= 0.01 then return true end

    local ignoreList = { Players.LocalPlayer.Character }
    local params = RaycastParams.new()
    params.FilterType = Enum.RaycastFilterType.Blacklist
    params.FilterDescendantsInstances = ignoreList

    while true do
        local result = Workspace:Raycast(origin, direction, params)
        if not result then return true end

        local hit = result.Instance
        if hit:IsDescendantOf(char) then return true end

        if hit:IsA("BasePart") and (hit.Transparency or 0) > 0.4 and not hit.CanCollide then
            -- Punch through transparent non-colliding parts (glass, decorative)
            table.insert(ignoreList, hit)
            params.FilterDescendantsInstances = ignoreList
            local dirUnit = direction.Unit
            origin = result.Position + dirUnit * 0.05
            direction = root.Position - origin
            if direction.Magnitude <= 0.01 then return true end
        else
            return false
        end
    end
end

function Targeting.getBestTarget(exclude)
    local localPlayer = Players.LocalPlayer
    local myRoot = rootOf(localPlayer.Character)
    if not myRoot then return nil end

    local visCheck = state.visibilityCheckEnabled
    local closestPlr, closestDist = nil, math.huge

    for _, plr in ipairs(Players:GetPlayers()) do
        if plr ~= localPlayer and plr ~= exclude and not state.isFriendly(plr) then
            local char = plr.Character
            local root = rootOf(char)
            if root and isInFront(root) and isAlive(char) and (not visCheck or isVisible(plr)) then
                local dist = (root.Position - myRoot.Position).Magnitude
                if (state.rangeLimit <= 0 or dist <= state.rangeLimit) and dist < closestDist then
                    closestDist = dist
                    closestPlr  = plr
                end
            end
        end
    end
    return closestPlr
end

return Targeting
end

_MODULES["modules.aim.highlight"] = function()
-- Target highlights + optional self-fade. Ports LockOnVisualModule.

local state = require("modules.aim.state")

local Players = game:GetService("Players")

local Highlight = {}

local highlights = {} -- [Player] = Highlight instance

local function setOne(plr, color, on)
    local h = highlights[plr]
    if on then
        local char = plr.Character
        if not char then
            if h then h:Destroy() end
            highlights[plr] = nil
            return
        end
        if not h or not h.Parent then
            h = Instance.new("Highlight")
            h.Name = "PantheonLockOnHighlight"
            highlights[plr] = h
        end
        h.Adornee = char
        h.FillColor = color
        h.FillTransparency = 0.5
        h.OutlineColor = color
        h.OutlineTransparency = 0
        h.DepthMode = Enum.HighlightDepthMode.AlwaysOnTop
        h.Parent = char
    else
        if h then h:Destroy() end
        highlights[plr] = nil
    end
end

function Highlight.clearAll()
    for plr in pairs(highlights) do
        setOne(plr, Color3.new(1, 0, 0), false)
    end
end

function Highlight.update(currentTarget, getSecondFn)
    Highlight.clearAll()
    if not state.highlightEnabled or not currentTarget then return end

    if not state.isFriendly(currentTarget) then
        setOne(currentTarget, Color3.new(1, 0, 0), true)
    end

    if state.highlightSecondEnabled and getSecondFn then
        local second = getSecondFn(currentTarget)
        if second and not state.isFriendly(second) then
            setOne(second, Color3.new(1, 1, 0), true)
        end
    end
end

local function applySelfFade(char)
    if not char then return end
    for _, d in ipairs(char:GetDescendants()) do
        if d:IsA("BasePart") then
            d.LocalTransparencyModifier = state.selfFadeEnabled and 0.6 or 0
        elseif d:IsA("Decal") then
            d.Transparency = state.selfFadeEnabled and 0.6 or 0
        end
    end
end

function Highlight.setSelfFade(v)
    state.selfFadeEnabled = v and true or false
    applySelfFade(Players.LocalPlayer.Character)
end

function Highlight.setEnabled(v)
    state.highlightEnabled = v and true or false
    if not v then Highlight.clearAll() end
end

function Highlight.setSecondEnabled(v)
    state.highlightSecondEnabled = v and true or false
end

function Highlight.init()
    Players.LocalPlayer.CharacterAdded:Connect(function(char)
        if state.selfFadeEnabled then
            char:WaitForChild("HumanoidRootPart", 5)
            applySelfFade(char)
        end
    end)
end

return Highlight
end

_MODULES["modules.aim.shiftlock"] = function()
-- Custom shiftlock. Ports ShiftLockModule with three improvements:
--   1. BindToRenderStep at Camera+100 (deterministic timing vs RenderStepped
--      competitors).
--   2. On enable AND on disable, sweeps PlayerGui for ScreenGuis matching
--      known foreign shiftlock GUI names and Destroys them.
--   3. On enable AND on disable, uses getconnections + getupvalues to find
--      foreign RenderStepped/Heartbeat connections that look like a shiftlock
--      loop (upvalue table has both `shiftLocked` and `humanoid`/`character`)
--      and Disconnects them. This is what actually frees the mouse when
--      another script's shiftlock is still running — without it, killing the
--      GUI doesn't stop the foreign loop, and that loop keeps re-locking the
--      mouse every frame.
--
-- The externalSkipRotation gate from the legacy module is preserved so LockOn+
-- can still take over rotation cleanly without two CFrame writes per frame.

local state = require("modules.aim.state")
local log   = require("core.log")

local Players          = game:GetService("Players")
local UserInputService = game:GetService("UserInputService")
local RunService       = game:GetService("RunService")

local Shiftlock = {}

local RENDER_BIND = "PantheonShiftlock"
local GUI_NAME    = "PantheonShiftLockVGui"

-- ScreenGui names commonly used by other custom shiftlock scripts. Doesn't
-- include our own GUI_NAME so the sweep never touches us.
local FOREIGN_GUI_NAMES = {
    "ShiftLockVGui", "ShiftLockIcon", "ShiftLockHud", "ShiftLockButton",
    "CustomShiftLock", "ShiftLockGui", "ShiftlockGui",
}

local self_state = {
    character = nil,
    humanoid  = nil,
    root      = nil,
    gui       = nil,
    vIcon     = nil,
    charConn  = nil,
    humConn   = nil,
    focusConn = nil,
    externalSkipRotation = nil,
    bound = false,
}

local function lp() return Players.LocalPlayer end

local function disableGameShiftLock()
    pcall(function() lp().DevEnableMouseLock = false end)
end

local function killForeignGuis()
    local pg = lp():FindFirstChildOfClass("PlayerGui")
    if not pg then return 0 end
    local count = 0
    for _, gui in ipairs(pg:GetChildren()) do
        if gui:IsA("ScreenGui") and gui.Name ~= GUI_NAME then
            for _, foreign in ipairs(FOREIGN_GUI_NAMES) do
                if gui.Name == foreign then
                    gui:Destroy()
                    count = count + 1
                    break
                end
            end
        end
    end
    return count
end

-- Walk RenderStepped + Heartbeat connections looking for ones whose upvalues
-- contain a table that looks like a shiftlock state object (has a `shiftLocked`
-- field AND a `humanoid` or `character` instance reference). Our own code uses
-- BindToRenderStep + Heartbeat with state.lua's flat state table (no humanoid
-- field), so this heuristic does not catch us.
local function killForeignLoops()
    if not getconnections then return 0 end
    local getU = rawget(getfenv(), "getupvalues") or (debug and debug.getupvalues)
    if not getU then return 0 end

    local function looksLikeShiftlockState(t)
        if type(t) ~= "table" then return false end
        local hasFlag    = (t.shiftLocked ~= nil) or (t.shiftlock_locked ~= nil)
        local hasInstRef = (typeof(t.humanoid) == "Instance")
                         or (typeof(t.character) == "Instance")
                         or (typeof(t.root) == "Instance")
        return hasFlag and hasInstRef
    end

    local function shouldKill(conn)
        local ok, fn = pcall(function() return conn.Function end)
        if not ok or type(fn) ~= "function" then
            ok, fn = pcall(function() return conn.Func end)
            if not ok or type(fn) ~= "function" then return false end
        end
        local ok2, ups = pcall(getU, fn)
        if not ok2 or type(ups) ~= "table" then return false end
        for _, up in pairs(ups) do
            if looksLikeShiftlockState(up) then return true end
        end
        return false
    end

    local count = 0
    for _, signal in ipairs({ RunService.RenderStepped, RunService.Heartbeat }) do
        local ok, conns = pcall(getconnections, signal)
        if ok and type(conns) == "table" then
            for _, conn in pairs(conns) do
                if shouldKill(conn) then
                    local dok = pcall(function() conn:Disconnect() end)
                    if dok then count = count + 1 end
                end
            end
        end
    end
    return count
end

local function buildGui()
    if self_state.gui and self_state.gui.Parent then return end
    local pg = lp():WaitForChild("PlayerGui")

    local gui = Instance.new("ScreenGui")
    gui.Name = GUI_NAME
    gui.ResetOnSpawn = false
    gui.IgnoreGuiInset = true
    gui.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
    gui.Parent = pg

    local vIcon = Instance.new("ImageLabel")
    vIcon.Name = "VIcon"
    vIcon.BackgroundTransparency = 1
    vIcon.Size = UDim2.new(0, 150, 0, 150)
    vIcon.AnchorPoint = Vector2.new(0.5, 0.5)
    vIcon.Position = UDim2.new(0.5, 0, 0.5, 0)
    vIcon.Visible = false
    vIcon.Image = "rbxassetid://18913450789"
    vIcon.ScaleType = Enum.ScaleType.Fit
    vIcon.BorderSizePixel = 5
    vIcon.BorderColor3 = Color3.new(1, 1, 1)
    vIcon.Parent = gui

    self_state.gui = gui
    self_state.vIcon = vIcon
end

local function updateCharRefs(char)
    self_state.character = char
    self_state.humanoid  = char:WaitForChild("Humanoid")
    self_state.root      = char:WaitForChild("HumanoidRootPart")

    if self_state.humConn then self_state.humConn:Disconnect() end
    self_state.humConn = self_state.humanoid.Died:Connect(function()
        state.shiftlock_active = false
        Shiftlock.forceOff()
    end)
end

local function applyLock()
    state.shiftlock_active = true
    disableGameShiftLock()
    if self_state.humanoid then self_state.humanoid.AutoRotate = false end
    if self_state.vIcon    then self_state.vIcon.Visible = true end
    UserInputService.MouseIconEnabled = false
    UserInputService.MouseBehavior    = Enum.MouseBehavior.LockCenter
end

function Shiftlock.forceOff()
    state.shiftlock_active = false
    if self_state.humanoid then self_state.humanoid.AutoRotate = true end
    if self_state.vIcon    then self_state.vIcon.Visible = false end
    UserInputService.MouseIconEnabled = true
    UserInputService.MouseBehavior    = Enum.MouseBehavior.Default
end

function Shiftlock.toggle()
    if not state.shiftlock_enabled then
        Shiftlock.setEnabled(true)
    end
    if state.shiftlock_active then
        Shiftlock.forceOff()
    else
        applyLock()
    end
end

local function reportKills(g, l, suffix)
    if g > 0 or l > 0 then
        log.info("shiftlock:", g, "GUI(s) +", l, "loop(s) killed " .. suffix)
    end
end

function Shiftlock.setEnabled(v)
    v = v and true or false
    if state.shiftlock_enabled == v then return end
    state.shiftlock_enabled = v
    if v then
        disableGameShiftLock()
        if state.killForeign then
            reportKills(killForeignGuis(), killForeignLoops(), "(enable)")
        end
    else
        Shiftlock.forceOff()
        -- Kill foreigns here too — otherwise a competing loop keeps holding
        -- MouseBehavior=LockCenter every frame after we release, so the user
        -- sees "the shiftlock didn't actually turn off."
        if state.killForeign then
            reportKills(killForeignGuis(), killForeignLoops(), "(disable)")
        end
    end
end

function Shiftlock.setExternalSkipRotation(fn)
    self_state.externalSkipRotation = fn
end

local function step()
    if not state.shiftlock_enabled then return end

    local hum = self_state.humanoid
    if hum then hum.CameraOffset = Vector3.new(0, 0, 0) end

    if not state.shiftlock_active or not self_state.root or not hum then return end
    if hum.PlatformStand or hum.Health <= 0 then return end

    local st = hum:GetState()
    if st == Enum.HumanoidStateType.Ragdoll
       or st == Enum.HumanoidStateType.FallingDown
       or st == Enum.HumanoidStateType.Physics
       or st == Enum.HumanoidStateType.Dead then
        return
    end

    if UserInputService.MouseBehavior ~= Enum.MouseBehavior.LockCenter then
        UserInputService.MouseBehavior = Enum.MouseBehavior.LockCenter
    end

    -- Yield rotation to LockOn+ when it's actively rotating to a target
    if self_state.externalSkipRotation and self_state.externalSkipRotation() then
        return
    end

    local cam = workspace.CurrentCamera
    if not cam then return end
    local look = cam.CFrame.LookVector
    local flat = Vector3.new(look.X, 0, look.Z)
    if flat.Magnitude > 0 then
        self_state.root.CFrame = CFrame.lookAt(self_state.root.Position, self_state.root.Position + flat)
    end
end

function Shiftlock.init()
    buildGui()

    local char = lp().Character or lp().CharacterAdded:Wait()
    updateCharRefs(char)

    self_state.charConn = lp().CharacterAdded:Connect(function(c)
        updateCharRefs(c)
        Shiftlock.forceOff()
        -- On respawn, foreign scripts may reconnect their loop against the new
        -- humanoid. Re-sweep so they don't quietly take over.
        if state.shiftlock_enabled and state.killForeign then
            task.defer(function()
                reportKills(killForeignGuis(), killForeignLoops(), "(respawn)")
            end)
        end
    end)

    self_state.focusConn = UserInputService.WindowFocusReleased:Connect(function()
        if state.shiftlock_active then Shiftlock.forceOff() end
    end)

    if not self_state.bound then
        RunService:BindToRenderStep(RENDER_BIND, Enum.RenderPriority.Camera.Value + 100, step)
        self_state.bound = true
    end

    -- Boot-time sweep. Foreign shiftlocks left over from another loaded script
    -- are what makes Pantheon "look enabled by default" (their loop locks the
    -- mouse regardless of our toggle). Wipe them on init so the user starts
    -- with a clean slate, not just on enable.
    if state.killForeign then
        task.defer(function()
            reportKills(killForeignGuis(), killForeignLoops(), "(boot)")
        end)
    end
end

function Shiftlock.destroy()
    if self_state.bound then
        pcall(function() RunService:UnbindFromRenderStep(RENDER_BIND) end)
        self_state.bound = false
    end
    Shiftlock.forceOff()
    if self_state.gui then self_state.gui:Destroy() end
    self_state.gui, self_state.vIcon = nil, nil
end

return Shiftlock
end

_MODULES["modules.aim.rotation_lock"] = function()
-- Rotation Lock (formerly Lock-On+): rotates the local body to face the
-- target while the camera stays free. Has its own keybind (default Q, set in
-- Lock-On's settings panel) with hold/toggle mode. Gated by:
--   - state.lockon_enabled       (Lock-On master toggle)
--   - state.rotationLockEnabled  (Rotation Lock sub-toggle)
--   - state.target               (Target Select has acquired someone)
--   - s.holdActive               (hotkey is engaged per hold/toggle mode)
-- Battlegrounds-safe gate (state.bgSafeEnabled) suppresses rotation while
-- either humanoid is in a non-walking state (ragdoll/falling/seated/etc.) and
-- gives a 0.15s smooth-resume window so the catch-up doesn't snap obviously.

local state = require("modules.aim.state")

local Players    = game:GetService("Players")
local RunService = game:GetService("RunService")

local RotationLock = {}

local BIND = "PantheonRotationLock"
local SMOOTH_DURATION = 0.15

local SUPPRESS_STATES = {
    [Enum.HumanoidStateType.Physics]          = true,
    [Enum.HumanoidStateType.FallingDown]      = true,
    [Enum.HumanoidStateType.Ragdoll]          = true,
    [Enum.HumanoidStateType.Seated]           = true,
    [Enum.HumanoidStateType.PlatformStanding] = true,
}

local s = {
    align           = nil,
    attachment      = nil,
    suppressedSince = 0,
    smoothUntil     = 0,
    bound           = false,
    holdMode        = true,   -- default: hold-to-engage
    holdActive      = false,  -- unified flag: true when rotation should engage
}

local function rootOf(charOrModel)
    return charOrModel and charOrModel:FindFirstChild("HumanoidRootPart")
end

local function targetCharacter()
    local t = state.target
    if not t then return nil end
    if state.target_type == "player" then return t.Character end
    return t
end

local function getHumanoids()
    local myChar = Players.LocalPlayer.Character
    local myHum  = myChar and myChar:FindFirstChildOfClass("Humanoid")
    local tChar  = targetCharacter()
    local tHum   = tChar and tChar:FindFirstChildOfClass("Humanoid")
    return myHum, tHum
end

local function shouldRotate()
    if not state.lockon_enabled then return false end
    if not state.rotationLockEnabled then return false end
    if not state.target then return false end
    if not s.holdActive then return false end
    return true
end

local function bgSuppressed()
    if not state.bgSafeEnabled then return false end
    local myHum, tHum = getHumanoids()
    if myHum then
        if myHum.PlatformStand then return true end
        if SUPPRESS_STATES[myHum:GetState()] then return true end
    end
    if tHum then
        if tHum.PlatformStand then return true end
        if SUPPRESS_STATES[tHum:GetState()] then return true end
    end
    return false
end

local function ensureConstraint(myRoot)
    if not s.attachment or not s.attachment.Parent then
        s.attachment = Instance.new("Attachment")
        s.attachment.Name = "PantheonRotationLockAttachment"
        s.attachment.Parent = myRoot
    end
    if not s.align or not s.align.Parent then
        s.align = Instance.new("AlignOrientation")
        s.align.Name = "PantheonRotationLockAlign"
        s.align.Mode = Enum.OrientationAlignmentMode.OneAttachment
        s.align.Attachment0 = s.attachment
        s.align.RigidityEnabled = true
        s.align.Responsiveness = 200
        s.align.MaxTorque = math.huge
        s.align.Parent = myRoot
    end
end

local function disableAlign()
    if s.align then s.align.Enabled = false end
end

local function step()
    if not shouldRotate() then
        disableAlign()
        return
    end

    local myChar = Players.LocalPlayer.Character
    if not myChar then return end
    local myRoot = rootOf(myChar)
    local myHum  = myChar:FindFirstChildOfClass("Humanoid")
    if not myRoot or not myHum then return end

    local tRoot = rootOf(targetCharacter())
    if not tRoot then return end

    if bgSuppressed() then
        s.suppressedSince = os.clock()
        disableAlign()
        return
    end

    local now = os.clock()
    if s.suppressedSince > 0 then
        s.smoothUntil = now + SMOOTH_DURATION
        s.suppressedSince = 0
    end

    local dir = tRoot.Position - myRoot.Position
    local flat = Vector3.new(dir.X, 0, dir.Z)
    if flat.Magnitude < 0.1 then return end

    myHum.AutoRotate = false
    ensureConstraint(myRoot)
    if s.align then
        s.align.Enabled = true
        s.align.CFrame = CFrame.lookAt(Vector3.zero, flat)
    end

    if now >= s.smoothUntil then
        local cf = CFrame.lookAt(myRoot.Position, myRoot.Position + flat)
        local _, yAngle, _ = cf:ToEulerAnglesYXZ()
        myRoot.CFrame = CFrame.new(myRoot.Position) * CFrame.Angles(0, yAngle, 0)
    end
end

function RotationLock.hotkeyPress()
    if not state.rotationLockEnabled then return end
    if s.holdMode then
        s.holdActive = true
    else
        s.holdActive = not s.holdActive
    end
end

function RotationLock.hotkeyRelease()
    if s.holdMode then
        s.holdActive = false
    end
end

function RotationLock.setHoldMode(v)
    s.holdMode = v and true or false
    -- Switching to toggle mode while engaged would leave holdActive stuck on.
    if not s.holdMode then s.holdActive = false end
end

function RotationLock.setEnabled(v)
    state.rotationLockEnabled = v and true or false
    if not v then
        s.holdActive = false
        disableAlign()
    end
end

-- True when Rotation Lock is currently driving the body. Shiftlock uses this
-- to yield: when Rotation Lock is active, shiftlock skips its own rotation.
function RotationLock.isActive()
    return shouldRotate() and not bgSuppressed()
end

function RotationLock.init()
    if s.bound then return end
    RunService:BindToRenderStep(BIND, Enum.RenderPriority.Camera.Value + 150, step)
    s.bound = true
end

function RotationLock.destroy()
    if s.bound then
        pcall(function() RunService:UnbindFromRenderStep(BIND) end)
        s.bound = false
    end
    if s.align then pcall(function() s.align:Destroy() end); s.align = nil end
    if s.attachment then pcall(function() s.attachment:Destroy() end); s.attachment = nil end
end

return RotationLock
end

_MODULES["modules.aim.lockon"] = function()
-- Lock-On: aim-assist applicator. Reads target from Target Select, applies
-- the camera force when state.lockon_enabled AND state.cameraLockEnabled AND a
-- target exists. Resistance gate is the same dt-scaled exponential approach.
--
-- Rotation Lock lives in a separate module (rotation_lock.lua) with its own
-- keybind and hold/toggle mode.

local state = require("modules.aim.state")

local RunService = game:GetService("RunService")

local LockOn = {}

local CAM_BIND = "PantheonLockOnCamera"

local s = {
    bound   = false,
    lastDir = nil,
}

local function rootOf(charOrModel)
    return charOrModel and charOrModel:FindFirstChild("HumanoidRootPart")
end

local function targetCharacter()
    local t = state.target
    if not t then return nil end
    if state.target_type == "player" then return t.Character end
    return t
end

local function cameraStep(dt)
    if not state.lockon_enabled then return end
    if not state.cameraLockEnabled then return end
    if not state.target then return end

    local cam = workspace.CurrentCamera
    if not cam then return end

    local tRoot = rootOf(targetCharacter())
    if not tRoot then return end

    local camPos  = cam.CFrame.Position
    local lookPos = tRoot.Position + Vector3.new(0, state.lockHeightOffset or 0, 0)
    local desired = lookPos - camPos
    if desired.Magnitude < 0.5 then
        if s.lastDir then
            cam.CFrame = CFrame.new(camPos, camPos + s.lastDir)
        end
        return
    end
    local dir = desired.Unit

    if state.resistance_enabled then
        local currentLook = cam.CFrame.LookVector
        local cosTheta = math.clamp(currentLook:Dot(dir), -1, 1)
        local angleDeg = math.deg(math.acos(cosTheta))
        if angleDeg < (state.resistance_threshold or 0) then
            s.lastDir = currentLook
            return
        end
        local smoothness = (state.resistance_strength or 0.5) * 20
        local alpha = 1 - math.exp(-smoothness * (dt or 1/60))
        local blended = currentLook:Lerp(dir, alpha)
        if blended.Magnitude > 0.001 then dir = blended.Unit end
    end

    s.lastDir = dir
    cam.CFrame = CFrame.new(camPos, camPos + dir)
end

function LockOn.setEnabled(v)
    state.lockon_enabled = v and true or false
end

function LockOn.init()
    if s.bound then return end
    RunService:BindToRenderStep(CAM_BIND, Enum.RenderPriority.Camera.Value + 1, cameraStep)
    s.bound = true
end

function LockOn.destroy()
    if s.bound then
        pcall(function() RunService:UnbindFromRenderStep(CAM_BIND) end)
        s.bound = false
    end
end

return LockOn
end

_MODULES["modules.aim.target_select"] = function()
-- Target Select: picks and holds a target, triggers Highlight. Lock-On and
-- Rotation Lock read state.target to know who to aim at. Owns the toggle/hold
-- hotkey (default X).

local state     = require("modules.aim.state")
local targeting = require("modules.aim.targeting")
local highlight = require("modules.aim.highlight")

local RunService = game:GetService("RunService")

local TargetSelect = {}

local s = {
    holdMode   = false,
    holdActive = false,
    heartConn  = nil,
}

local function releaseTarget()
    state.setTarget(nil, nil)
    s.holdActive = false
    highlight.update(nil, nil)
end

local function engageTarget()
    local t = targeting.getBestTarget()
    if not t then return false end
    state.setTarget(t, "player")
    return true
end

function TargetSelect.swapTarget()
    if not state.swap_enabled then return end
    if not state.target_select_enabled or not state.target then return end
    local next_ = targeting.getBestTarget(state.target)
    if next_ then state.setTarget(next_, "player") end
end

local function step()
    if not state.target_select_enabled then return end
    if not state.target then return end

    local t = state.target
    if state.target_type == "player" then
        local char = t and t.Character
        local hum  = char and char:FindFirstChildOfClass("Humanoid")
        if not hum or hum.Health <= 0 or not char.Parent or state.isFriendly(t) then
            releaseTarget()
            return
        end
    elseif state.target_type == "npc" then
        local hum = t and t:FindFirstChildOfClass("Humanoid")
        if not hum or hum.Health <= 0 or not t.Parent then
            releaseTarget()
            return
        end
    end

    highlight.update(t, function(exclude) return targeting.getBestTarget(exclude) end)
end

function TargetSelect.hotkeyPress()
    if not state.target_select_enabled then return end
    if s.holdMode then
        if not state.target then engageTarget() end
        s.holdActive = true
    else
        if state.target then releaseTarget() else engageTarget() end
    end
end

function TargetSelect.hotkeyRelease()
    if s.holdMode and s.holdActive and state.target then
        releaseTarget()
    end
end

function TargetSelect.setHoldMode(v)
    s.holdMode = v and true or false
end

function TargetSelect.setEnabled(v)
    state.target_select_enabled = v and true or false
    if not v then releaseTarget() end
end

function TargetSelect.init()
    s.heartConn = RunService.Heartbeat:Connect(step)
end

function TargetSelect.destroy()
    if s.heartConn then s.heartConn:Disconnect(); s.heartConn = nil end
end

return TargetSelect
end

_MODULES["modules.aim.init"] = function()
-- Aim Assist: declarative feature definitions across three categories.
-- Target Select picks the target, Lock-On applies aim assist (camera + rotation
-- sub-toggles), Highlight reflects the selected target.

local window       = require("ui.window")
local container    = require("ui.container")
local feature      = require("ui.feature")
local state        = require("modules.aim.state")
local highlight    = require("modules.aim.highlight")
local shiftlock    = require("modules.aim.shiftlock")
local rotationLock = require("modules.aim.rotation_lock")
local lockon       = require("modules.aim.lockon")
local targetSelect = require("modules.aim.target_select")
local log          = require("core.log")

local module = {}

function module.register()
    -- Boot the implementations
    highlight.init()
    shiftlock.init()
    rotationLock.init()
    lockon.init()
    targetSelect.init()
    shiftlock.setExternalSkipRotation(rotationLock.isActive)

    local parent = window.parent()

    -- 1. Movement -------------------------------------------------------------
    local move = container.new(parent, "Movement")
    move:add(feature.declare({
        id          = "aim.shiftlock",
        name        = "Custom Shiftlock",
        description = "Locks your mouse to the center of the screen and rotates your character to face the camera. Replaces Roblox's built-in shift-lock and disconnects competing shift-lock loops from other scripts on enable, disable, and boot.",
        default     = false,
        defaultKey  = Enum.KeyCode.LeftShift,
        onToggle    = function(v) shiftlock.setEnabled(v) end,
        onKey       = function()
            if not state.shiftlock_enabled then
                shiftlock.setEnabled(true)
            end
            shiftlock.toggle()
        end,
        settings = {
            { type = "toggle", name = "Kill foreign shiftlock GUIs / loops", default = true,
              onChange = function(v) state.killForeign = v end },
        },
    }).root)

    -- 2. Combat ---------------------------------------------------------------
    local combat = container.new(parent, "Combat")

    -- Target Select: owns the X hotkey, picks targets, triggers Highlight.
    combat:add(feature.declare({
        id           = "aim.target_select",
        name         = "Target Select",
        description  = "Picks the nearest valid target (with optional FOV / health / visibility / range filters) and triggers the Highlight. Lock-On and Rotation Lock read the chosen target. Hold-mode releases when you release the key; toggle-mode latches.",
        default      = false,
        defaultKey   = Enum.KeyCode.X,
        onToggle     = function(v) targetSelect.setEnabled(v) end,
        onKey        = function() targetSelect.hotkeyPress()   end,
        onKeyRelease = function() targetSelect.hotkeyRelease() end,
        settings = {
            { type = "toggle", name = "Hold mode (vs toggle)", default = false,
              onChange = function(v) targetSelect.setHoldMode(v) end },
            { type = "toggle", name = "Skip dead / shielded", default = true,
              onChange = function(v) state.checkHealthEnabled = v end },
            { type = "slider", name = "Range (0 = inf)",
              min = 0, max = 500, step = 5, default = 0,
              onChange = function(v) state.rangeLimit = v end },
        },
    }).root)

    -- Lock-On: aim-assist applicator. Master toggle plus sub-toggles for
    -- Camera Lock and Rotation Lock so the user can mix-and-match.
    combat:add(feature.declare({
        id          = "aim.lockon",
        name        = "Lock-On",
        description = "Applies aim assist to the target picked by Target Select. Sub-toggles let you mix the type: Camera Lock forces the camera to look at the target, Rotation Lock (its own keybind) spins your body to face them. Resistance gives you a free-aim deadzone before the camera pull kicks in.",
        default     = false,
        onToggle    = function(v) lockon.setEnabled(v) end,
        settings = {
            { type = "section", name = "Types" },
            { type = "toggle", name = "Camera Lock", default = true,
              onChange = function(v) state.cameraLockEnabled = v end },
            { type = "toggle", name = "Rotation Lock", default = false,
              onChange = function(v) rotationLock.setEnabled(v) end },
            { type = "keybind", name = "Rotation Lock key",
              id       = "aim.rotation_lock",
              default  = Enum.KeyCode.Q,
              onPress  = function() rotationLock.hotkeyPress()   end,
              onRelease= function() rotationLock.hotkeyRelease() end },
            { type = "toggle", name = "Rotation Lock hold mode", default = true,
              onChange = function(v) rotationLock.setHoldMode(v) end },
            { type = "toggle", name = "Battlegrounds-safe", default = true,
              onChange = function(v) state.bgSafeEnabled = v end },

            { type = "section", name = "Resistance" },
            { type = "toggle", name = "Enable Resistance", default = false,
              onChange = function(v) state.resistance_enabled = v end },
            { type = "slider", name = "Threshold (deg)",
              min = 0, max = 30, step = 1, default = 5,
              onChange = function(v) state.resistance_threshold = v end },
            { type = "slider", name = "Strength",
              min = 0.05, max = 1, step = 0.05, default = 0.5,
              onChange = function(v) state.resistance_strength = v end },
        },
    }).root)

    -- Swap Target: cycles to the next-best target while Target Select is engaged.
    combat:add(feature.declare({
        id          = "aim.swap_target",
        name        = "Swap Target",
        description = "While Target Select has a target, press this key to cycle to the next-best target.",
        default     = true,
        defaultKey  = Enum.KeyCode.C,
        onToggle    = function(v) state.swap_enabled = v end,
        onKey       = function() targetSelect.swapTarget() end,
    }).root)

    -- 3. Visuals --------------------------------------------------------------
    local vis = container.new(parent, "Visuals")
    vis:add(feature.declare({
        id          = "aim.highlight",
        name        = "Highlight",
        description = "Outlines whichever target Target Select picks: red on the active target, optional yellow on the next-best. Self-fade drops your own character's opacity so you don't get blocked by your own back.",
        default     = true,
        onToggle    = function(v) highlight.setEnabled(v) end,
        settings = {
            { type = "toggle", name = "Highlight next-best (yellow)", default = false,
              onChange = function(v) highlight.setSecondEnabled(v) end },
            { type = "toggle", name = "Self-fade", default = false,
              onChange = function(v) highlight.setSelfFade(v) end },
        },
    }).root)

    log.info("Aim Assist registered (Movement / Combat / Visuals)")
end

return module
end

_MODULES["init"] = function()
-- Pantheon entry point. Boots keybinds + window, registers modules.

local log      = require("core.log")
local env      = require("core.env")
local keybinds = require("core.keybinds")
local window   = require("ui.window")
local notify   = require("ui.notify")
local registry = require("games.registry")

log.info("booting on executor:", env.executor)

keybinds.init()
window.init()

-- Universal modules
do
    local aim = require("modules.aim.init")
    aim.register()
end

-- Per-game module (if registered for this PlaceId)
local gameMod = registry.current()
if gameMod and gameMod.register then
    log.info("game module found for PlaceId", game.PlaceId)
    local ok, err = pcall(gameMod.register)
    if not ok then log.err("game module register failed:", err) end
else
    log.info("no game module for PlaceId", game.PlaceId)
end

notify.success("Pantheon loaded. Press RightCtrl to toggle UI.")

return true
end


return require("init")
